package org.apache.kafka.common.record.internal;

import org.apache.kafka.common.InvalidRecordException;
import org.apache.kafka.common.KafkaException;
import org.apache.kafka.common.compress.Compression;
import org.apache.kafka.common.errors.CorruptRecordException;
import org.apache.kafka.common.header.Header;
import org.apache.kafka.common.record.TimestampType;
import org.apache.kafka.common.utils.BufferSupplier;
import org.apache.kafka.common.utils.ByteBufferOutputStream;
import org.apache.kafka.common.utils.ByteUtils;
import org.apache.kafka.common.utils.CloseableIterator;
import org.apache.kafka.common.utils.Crc32C;

import java.io.IOException;
import java.io.InputStream;
import java.nio.BufferUnderflowException;
import java.nio.ByteBuffer;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Iterator;
import java.util.List;
import java.util.NoSuchElementException;
import java.util.Objects;
import java.util.OptionalLong;

import static org.apache.kafka.common.record.internal.Records.LOG_OVERHEAD;

/**
 * {@link RecordBatch} implementation for magic version 2 and above. This class encapsulates the
 * binary serialization format of a Kafka record batch, including the batch header and all contained
 * records.
 *
 * <p><strong>Binary Format:</strong> The batch follows the RecordBatch schema:
 * <pre>
 * RecordBatch =>
 *  BaseOffset => Int64
 *  Length => Int32
 *  PartitionLeaderEpoch => Int32
 *  Magic => Int8
 *  CRC => Uint32
 *  Attributes => Int16
 *  LastOffsetDelta => Int32
 *  BaseTimestamp => Int64
 *  MaxTimestamp => Int64
 *  ProducerId => Int64
 *  ProducerEpoch => Int16
 *  BaseSequence => Int32
 *  RecordsCount => Int32
 *  Records => [Record]
 * </pre>
 * When compression is enabled, the compressed record data follows immediately after the record count.
 *
 * <p><strong>CRC Computation:</strong> The CRC-32C (Castagnoli) polynomial is used and covers all
 * bytes from the attributes field through the end of the batch. The partition leader epoch field is
 * excluded from CRC computation to avoid recomputation when the broker assigns a leader epoch.
 *
 * <p><strong>Log Compaction:</strong> Unlike older message formats, magic v2 batches preserve the
 * first and last offset/sequence numbers from the original batch during log compaction. This preservation
 * is critical for: (1) restoring producer state on broker restart, and (2) duplicate detection via
 * sequence number verification. Empty batches may be retained to preserve producer sequence information
 * until a new sequence is written or the producer ID expires.
 *
 * <p><strong>Timestamp Semantics:</strong>
 * <ul>
 *   <li>BaseTimestamp: For CREATE_TIME, reflects the first record's timestamp. After compaction,
 *       reflects the first remaining record. For LOG_APPEND_TIME, set by the broker. If the
 *       delete horizon flag is set, BaseTimestamp contains the horizon timestamp for cleanup.</li>
 *   <li>MaxTimestamp: For CREATE_TIME, the maximum timestamp among current records and updated during
 *       compaction. For LOG_APPEND_TIME, set by the broker and preserved across compaction.</li>
 * </ul>
 *
 * <p><strong>Batch Attributes:</strong> Encoded in a 16-bit field with the following structure:
 * <pre>
 *  Bits 0-2:   Compression Type (0=None, 1=GZIP, 2=Snappy, 3=LZ4, 4=ZSTD)
 *  Bit 3:      Timestamp Type (0=CreateTime, 1=LogAppendTime)
 *  Bit 4:      Is Transactional
 *  Bit 5:      Is Control Batch
 *  Bit 6:      Delete Horizon Flag
 *  Bits 7-15:  Reserved (unused)
 * </pre>
 *
 * <p><strong>Thread-safety:</strong> {@code DefaultRecordBatch} is <strong>not thread-safe</strong>.
 * The underlying ByteBuffer backing a batch is mutable and can be modified by multiple threads.
 * To ensure thread-safety: (1) do not share batch instances across threads, or (2) use external
 * synchronization if sharing is necessary, or (3) wrap the batch operations with immutable views.
 * Multiple distinct batch instances can be safely accessed in parallel from different threads.
 *
 * <p><strong>Performance Characteristics:</strong>
 * <ul>
 *   <li>Header access (offset, timestamp, producer id, etc.) is O(1)</li>
 *   <li>Record iteration is O(n) but amortized per-record cost is minimal for uncompressed batches</li>
 *   <li>Decompression on iteration can be a bottleneck; use {@link #streamingIterator(BufferSupplier)}
 *       with buffer reuse for memory efficiency on large batches</li>
 *   <li>CRC validation is O(n) in batch size and is performed lazily on demand</li>
 * </ul>
 *
 * @see RecordBatch
 * @see MemoryRecords
 * @see MemoryRecordsBuilder
 */
public class DefaultRecordBatch extends AbstractRecordBatch implements MutableRecordBatch {
    static final int BASE_OFFSET_OFFSET = 0;
    static final int BASE_OFFSET_LENGTH = 8;
    static final int LENGTH_OFFSET = BASE_OFFSET_OFFSET + BASE_OFFSET_LENGTH;
    static final int LENGTH_LENGTH = 4;
    static final int PARTITION_LEADER_EPOCH_OFFSET = LENGTH_OFFSET + LENGTH_LENGTH;
    static final int PARTITION_LEADER_EPOCH_LENGTH = 4;
    static final int MAGIC_OFFSET = PARTITION_LEADER_EPOCH_OFFSET + PARTITION_LEADER_EPOCH_LENGTH;
    static final int MAGIC_LENGTH = 1;
    public static final int CRC_OFFSET = MAGIC_OFFSET + MAGIC_LENGTH;
    static final int CRC_LENGTH = 4;
    static final int ATTRIBUTES_OFFSET = CRC_OFFSET + CRC_LENGTH;
    static final int ATTRIBUTE_LENGTH = 2;
    public static final int LAST_OFFSET_DELTA_OFFSET = ATTRIBUTES_OFFSET + ATTRIBUTE_LENGTH;
    static final int LAST_OFFSET_DELTA_LENGTH = 4;
    static final int BASE_TIMESTAMP_OFFSET = LAST_OFFSET_DELTA_OFFSET + LAST_OFFSET_DELTA_LENGTH;
    static final int BASE_TIMESTAMP_LENGTH = 8;
    static final int MAX_TIMESTAMP_OFFSET = BASE_TIMESTAMP_OFFSET + BASE_TIMESTAMP_LENGTH;
    static final int MAX_TIMESTAMP_LENGTH = 8;
    static final int PRODUCER_ID_OFFSET = MAX_TIMESTAMP_OFFSET + MAX_TIMESTAMP_LENGTH;
    static final int PRODUCER_ID_LENGTH = 8;
    static final int PRODUCER_EPOCH_OFFSET = PRODUCER_ID_OFFSET + PRODUCER_ID_LENGTH;
    static final int PRODUCER_EPOCH_LENGTH = 2;
    static final int BASE_SEQUENCE_OFFSET = PRODUCER_EPOCH_OFFSET + PRODUCER_EPOCH_LENGTH;
    static final int BASE_SEQUENCE_LENGTH = 4;
    public static final int RECORDS_COUNT_OFFSET = BASE_SEQUENCE_OFFSET + BASE_SEQUENCE_LENGTH;
    static final int RECORDS_COUNT_LENGTH = 4;
    static final int RECORDS_OFFSET = RECORDS_COUNT_OFFSET + RECORDS_COUNT_LENGTH;
    public static final int RECORD_BATCH_OVERHEAD = RECORDS_OFFSET;

    private static final byte COMPRESSION_CODEC_MASK = 0x07;
    private static final byte TRANSACTIONAL_FLAG_MASK = 0x10;
    private static final int CONTROL_FLAG_MASK = 0x20;
    private static final byte DELETE_HORIZON_FLAG_MASK = 0x40;
    private static final byte TIMESTAMP_TYPE_MASK = 0x08;

    private final ByteBuffer buffer;

    /**
     * Constructs a DefaultRecordBatch from a ByteBuffer. The buffer is expected to contain
     * a complete batch with valid header and record data. The buffer position and limit define
     * the boundaries of the batch data.
     *
     * <p><strong>Note:</strong> The batch maintains a reference to the provided buffer. Callers
     * should ensure the buffer remains valid and unmodified for the lifetime of the batch.
     *
     * @param buffer A ByteBuffer containing the serialized batch data. Must contain at least
     *               {@link #RECORD_BATCH_OVERHEAD} bytes.
     */
    DefaultRecordBatch(ByteBuffer buffer) {
        this.buffer = buffer;
    }

    @Override
    public byte magic() {
        return buffer.get(MAGIC_OFFSET);
    }

    /**
     * Validates the integrity of this record batch. Checks that the batch size is sufficient
     * to contain at least the batch header overhead, and that the CRC checksum is correct.
     *
     * @throws CorruptRecordException if the batch is smaller than the required overhead or
     *                                if the stored CRC does not match the computed CRC
     */
    @Override
    public void ensureValid() {
        if (sizeInBytes() < RECORD_BATCH_OVERHEAD)
            throw new CorruptRecordException("Record batch is corrupt (the size " + sizeInBytes() +
                    " is smaller than the minimum allowed overhead " + RECORD_BATCH_OVERHEAD + ")");

        if (!isValid())
            throw new CorruptRecordException("Record is corrupt (stored crc = " + checksum()
                    + ", computed crc = " + computeChecksum() + ")");
    }

    /**
     * Gets the base timestamp of the batch which is used as the reference for calculating
     * relative record timestamps (timestamp deltas). The interpretation of this value depends
     * on the timestamp type and whether the delete horizon flag is set.
     *
     * <p><strong>Semantics:</strong>
     * <ul>
     *   <li>If delete horizon is set: Contains the delete horizon timestamp for cleanup</li>
     *   <li>If CREATE_TIME: Timestamp of the first record in the batch (or first after compaction)</li>
     *   <li>If LOG_APPEND_TIME: Set by broker when batch is appended to log</li>
     *   <li>If batch is empty: Set to {@link RecordBatch#NO_TIMESTAMP}</li>
     * </ul>
     *
     * @return The base timestamp in milliseconds
     */
    public long baseTimestamp() {
        return buffer.getLong(BASE_TIMESTAMP_OFFSET);
    }

    @Override
    public long maxTimestamp() {
        return buffer.getLong(MAX_TIMESTAMP_OFFSET);
    }

    @Override
    public TimestampType timestampType() {
        return (attributes() & TIMESTAMP_TYPE_MASK) == 0 ? TimestampType.CREATE_TIME : TimestampType.LOG_APPEND_TIME;
    }

    @Override
    public long baseOffset() {
        return buffer.getLong(BASE_OFFSET_OFFSET);
    }

    @Override
    public long lastOffset() {
        return baseOffset() + lastOffsetDelta();
    }

    @Override
    public long producerId() {
        return buffer.getLong(PRODUCER_ID_OFFSET);
    }

    @Override
    public short producerEpoch() {
        return buffer.getShort(PRODUCER_EPOCH_OFFSET);
    }

    @Override
    public int baseSequence() {
        return buffer.getInt(BASE_SEQUENCE_OFFSET);
    }

    private int lastOffsetDelta() {
        return buffer.getInt(LAST_OFFSET_DELTA_OFFSET);
    }

    @Override
    public int lastSequence() {
        int baseSequence = baseSequence();
        if (baseSequence == RecordBatch.NO_SEQUENCE)
            return RecordBatch.NO_SEQUENCE;
        return incrementSequence(baseSequence, lastOffsetDelta());
    }

    @Override
    public CompressionType compressionType() {
        return CompressionType.forId(attributes() & COMPRESSION_CODEC_MASK);
    }

    @Override
    public int sizeInBytes() {
        return LOG_OVERHEAD + buffer.getInt(LENGTH_OFFSET);
    }

    private int count() {
        return buffer.getInt(RECORDS_COUNT_OFFSET);
    }

    @Override
    public Integer countOrNull() {
        return count();
    }

    /**
     * Writes this record batch to a ByteBuffer. Copies the entire batch including header and
     * all records to the provided buffer at its current position. The buffer's position is
     * updated by the number of bytes written.
     *
     * <p><strong>Performance note:</strong> This method performs a bulk copy of the underlying
     * ByteBuffer slice, which is efficient.
     *
     * @param buffer The target ByteBuffer to write to. Must have at least {@link #sizeInBytes()}
     *               remaining space.
     * @throws java.nio.BufferOverflowException if the buffer lacks sufficient remaining space
     */
    @Override
    public void writeTo(ByteBuffer buffer) {
        buffer.put(this.buffer.duplicate());
    }

    @Override
    public void writeTo(ByteBufferOutputStream outputStream) {
        outputStream.write(this.buffer.duplicate());
    }

    @Override
    public boolean isTransactional() {
        return (attributes() & TRANSACTIONAL_FLAG_MASK) > 0;
    }

    private boolean hasDeleteHorizonMs() {
        return (attributes() & DELETE_HORIZON_FLAG_MASK) > 0;
    }

    @Override
    public OptionalLong deleteHorizonMs() {
        if (hasDeleteHorizonMs())
            return OptionalLong.of(buffer.getLong(BASE_TIMESTAMP_OFFSET));
        else
            return OptionalLong.empty();
    }

    @Override
    public boolean isControlBatch() {
        return (attributes() & CONTROL_FLAG_MASK) > 0;
    }

    @Override
    public int partitionLeaderEpoch() {
        return buffer.getInt(PARTITION_LEADER_EPOCH_OFFSET);
    }

    /**
     * Creates an InputStream for reading the serialized record data from this batch.
     * If the batch is compressed, the returned stream will decompress the data on-the-fly.
     *
     * <p><strong>Resource management:</strong> The caller is responsible for closing the
     * returned InputStream to release decompression resources if the batch is compressed.
     *
     * @param bufferSupplier Supplies ByteBuffer(s) for decompression operations. For compressed
     *                       batches, this supplier's buffers are used during decompression.
     * @return An InputStream positioned at the first record's serialized bytes. For uncompressed
     *         batches, reads directly from the underlying ByteBuffer. For compressed batches,
     *         decompresses transparently.
     */
    public InputStream recordInputStream(BufferSupplier bufferSupplier) {
        final ByteBuffer buffer = this.buffer.duplicate();
        buffer.position(RECORDS_OFFSET);
        return Compression.of(compressionType()).build().wrapForInput(buffer, magic(), bufferSupplier);
    }

    private CloseableIterator<Record> compressedIterator(BufferSupplier bufferSupplier, boolean skipKeyValue) {
        final InputStream inputStream = recordInputStream(bufferSupplier);

        if (skipKeyValue) {
            return new StreamRecordIterator(inputStream) {
                @Override
                protected Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException {
                    return DefaultRecord.readPartiallyFrom(inputStream, baseOffset, baseTimestamp, baseSequence, logAppendTime);
                }
            };
        } else {
            return new StreamRecordIterator(inputStream) {
                @Override
                protected Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException {
                    return DefaultRecord.readFrom(inputStream, baseOffset, baseTimestamp, baseSequence, logAppendTime);
                }
            };
        }
    }

    private CloseableIterator<Record> uncompressedIterator() {
        final ByteBuffer buffer = this.buffer.duplicate();
        buffer.position(RECORDS_OFFSET);
        return new RecordIterator() {
            @Override
            protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
                try {
                    return DefaultRecord.readFrom(buffer, baseOffset, baseTimestamp, baseSequence, logAppendTime);
                } catch (BufferUnderflowException e) {
                    throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached");
                }
            }
            @Override
            protected boolean ensureNoneRemaining() {
                return !buffer.hasRemaining();
            }
            @Override
            public void close() {}
        };
    }

    /**
     * Returns an iterator over the records contained in this batch. For compressed batches,
     * the full batch is decompressed into memory. For efficiency with large compressed batches
     * that don't require holding all records in memory, use {@link #streamingIterator(BufferSupplier)}.
     *
     * <p><strong>Performance characteristics:</strong>
     * <ul>
     *   <li>Uncompressed: Minimal memory overhead, direct buffer reads</li>
     *   <li>Compressed: Full batch decompressed into memory upfront; use streamingIterator
     *       for streaming decompression if memory is a concern</li>
     * </ul>
     *
     * @return An Iterator over records. Never null; may return an empty iterator if the batch
     *         contains zero records.
     */
    @Override
    public Iterator<Record> iterator() {
        if (count() == 0)
            return Collections.emptyIterator();

        if (!isCompressed())
            return uncompressedIterator();

        // for a normal iterator, we cannot ensure that the underlying compression stream is closed,
        // so we decompress the full record set here. Use cases which call for a lower memory footprint
        // can use `streamingIterator` at the cost of additional complexity
        try (CloseableIterator<Record> iterator = compressedIterator(BufferSupplier.NO_CACHING, false)) {
            List<Record> records = new ArrayList<>(count());
            while (iterator.hasNext())
                records.add(iterator.next());
            return records.iterator();
        }
    }

    /**
     * Returns an iterator that skips key, value, and header data within records. This is useful
     * for validation and metrics collection where only record offset and timestamp are needed.
     *
     * <p><strong>Performance characteristics:</strong>
     * <ul>
     *   <li>Uncompressed: No benefit; uses standard uncompressed iterator as skipping is not efficient</li>
     *   <li>Compressed: Decompresses on-demand and skips serialized key/value/header data to save memory</li>
     * </ul>
     *
     * <p><strong>Resource management:</strong> The returned iterator should be closed to release
     * any decompression resources.
     *
     * @param bufferSupplier Supplies ByteBuffer(s) for decompression. For memory efficiency with
     *                       large compressed batches, provide a reusing supplier.
     * @return A closeable iterator over records, with key/value/headers not deserialized
     */
    @Override
    public CloseableIterator<Record> skipKeyValueIterator(BufferSupplier bufferSupplier) {
        if (count() == 0) {
            return CloseableIterator.wrap(Collections.emptyIterator());
        }

        /*
         * For uncompressed iterator, it is actually not worth skipping key / value / headers at all since
         * its ByteBufferInputStream's skip() function is less efficient compared with just reading it actually
         * as it will allocate new byte array.
         */
        if (!isCompressed())
            return uncompressedIterator();

        // we define this to be a closable iterator so that caller (i.e. the log validator) needs to close it
        // while we can save memory footprint of not decompressing the full record set ahead of time
        return compressedIterator(bufferSupplier, true);
    }

    /**
     * Returns a streaming iterator for records in this batch with deferred decompression.
     * For uncompressed batches, provides minimal overhead. For compressed batches, decompresses
     * data on-demand as records are consumed, reducing memory footprint compared to full upfront
     * decompression.
     *
     * <p><strong>Resource management:</strong> The returned iterator MUST be closed using
     * try-with-resources or explicit close() to properly release decompression resources.
     *
     * <p><strong>Performance notes:</strong>
     * <ul>
     *   <li>For large compressed batches, this method provides significant memory savings by avoiding
     *       full decompression until records are actually read</li>
     *   <li>The decompression buffer supplier significantly impacts performance; reusing buffers
     *       across multiple streaming iterators can be more efficient than allocating fresh buffers</li>
     * </ul>
     *
     * @param bufferSupplier Supplies decompression buffers. For optimal performance with multiple
     *                       iterations, provide a reusing supplier via {@link BufferSupplier} methods.
     * @return A closeable iterator that must be closed. Never null.
     * @throws KafkaException if decompression fails
     */
    @Override
    public CloseableIterator<Record> streamingIterator(BufferSupplier bufferSupplier) {
        if (isCompressed())
            return compressedIterator(bufferSupplier, false);
        else
            return uncompressedIterator();
    }

    /**
     * Sets the last offset for this batch by updating the base offset field. This method is
     * used during in-place offset assignment after log compaction or producer deduplication.
     *
     * <p><strong>Preconditions:</strong> This method modifies the underlying buffer. Callers
     * must ensure the batch is not concurrently accessed by other threads.
     *
     * <p><strong>Implementation note:</strong> Updates the base offset such that
     * {@code baseOffset() + lastOffsetDelta() == offset}.
     *
     * @param offset The new last offset (inclusive) for this batch
     */
    @Override
    public void setLastOffset(long offset) {
        buffer.putLong(BASE_OFFSET_OFFSET, offset - lastOffsetDelta());
    }

    /**
     * Updates the maximum timestamp and timestamp type of this batch. Used during log compaction
     * when record timestamps change. This method recomputes the CRC if the timestamp is actually updated.
     *
     * <p><strong>Preconditions:</strong> This method modifies the underlying buffer. Callers
     * must ensure the batch is not concurrently accessed.
     *
     * <p><strong>CRC behavior:</strong> If the timestamp type is the same and the max timestamp
     * value is unchanged, no CRC recomputation occurs. Otherwise, CRC is recomputed over the
     * updated batch.
     *
     * @param timestampType The new timestamp type ({@link TimestampType#CREATE_TIME} or
     *                      {@link TimestampType#LOG_APPEND_TIME})
     * @param maxTimestamp  The new maximum timestamp in milliseconds
     */
    @Override
    public void setMaxTimestamp(TimestampType timestampType, long maxTimestamp) {
        long currentMaxTimestamp = maxTimestamp();
        // We don't need to recompute crc if the timestamp is not updated.
        if (timestampType() == timestampType && currentMaxTimestamp == maxTimestamp)
            return;

        byte attributes = computeAttributes(compressionType(), timestampType, isTransactional(), isControlBatch(), hasDeleteHorizonMs());
        buffer.putShort(ATTRIBUTES_OFFSET, attributes);
        buffer.putLong(MAX_TIMESTAMP_OFFSET, maxTimestamp);
        long crc = computeChecksum();
        ByteUtils.writeUnsignedInt(buffer, CRC_OFFSET, crc);
    }

    /**
     * Sets the partition leader epoch for this batch. The partition leader epoch indicates
     * which broker leader epoch was in effect when this batch was written. This is set by the
     * broker and is not included in the CRC.
     *
     * <p><strong>Preconditions:</strong> This method modifies the underlying buffer.
     *
     * @param epoch The partition leader epoch (>= 0)
     */
    @Override
    public void setPartitionLeaderEpoch(int epoch) {
        buffer.putInt(PARTITION_LEADER_EPOCH_OFFSET, epoch);
    }

    @Override
    public long checksum() {
        return ByteUtils.readUnsignedInt(buffer, CRC_OFFSET);
    }

    /**
     * Validates the checksum of this batch by comparing the stored CRC against a freshly
     * computed CRC over the same data.
     *
     * <p><strong>Performance note:</strong> This method recomputes the CRC and is O(batch size).
     *
     * @return true if the stored checksum matches the computed checksum, false otherwise
     */
    public boolean isValid() {
        return sizeInBytes() >= RECORD_BATCH_OVERHEAD && checksum() == computeChecksum();
    }

    private long computeChecksum() {
        return Crc32C.compute(buffer, ATTRIBUTES_OFFSET, buffer.limit() - ATTRIBUTES_OFFSET);
    }

    private byte attributes() {
        // note we're not using the second byte of attributes
        return (byte) buffer.getShort(ATTRIBUTES_OFFSET);
    }

    @Override
    public boolean equals(Object o) {
        if (this == o)
            return true;
        if (o == null || getClass() != o.getClass())
            return false;

        DefaultRecordBatch that = (DefaultRecordBatch) o;
        return Objects.equals(buffer, that.buffer);
    }

    @Override
    public int hashCode() {
        return buffer != null ? buffer.hashCode() : 0;
    }

    private static byte computeAttributes(CompressionType type, TimestampType timestampType,
                                          boolean isTransactional, boolean isControl, boolean isDeleteHorizonSet) {
        if (timestampType == TimestampType.NO_TIMESTAMP_TYPE)
            throw new IllegalArgumentException("Timestamp type must be provided to compute attributes for message " +
                    "format v2 and above");

        byte attributes = isTransactional ? TRANSACTIONAL_FLAG_MASK : 0;
        if (isControl)
            attributes |= CONTROL_FLAG_MASK;
        if (type.id > 0)
            attributes |= (byte) (COMPRESSION_CODEC_MASK & type.id);
        if (timestampType == TimestampType.LOG_APPEND_TIME)
            attributes |= TIMESTAMP_TYPE_MASK;
        if (isDeleteHorizonSet)
            attributes |= DELETE_HORIZON_FLAG_MASK;
        return attributes;
    }

    /**
     * Writes an empty batch header to a ByteBuffer. An empty batch contains only the header
     * with zero records. Empty batches are retained during log compaction to preserve producer
     * sequence information.
     *
     * <p><strong>Use cases:</strong> Typically used when all records in a batch have been removed
     * during compaction, but the producer sequence state must be retained.
     *
     * @param buffer              The target ByteBuffer
     * @param magic               The magic version (must be {@link RecordBatch#CURRENT_MAGIC_VALUE})
     * @param producerId          The producer id
     * @param producerEpoch       The producer epoch
     * @param baseSequence        The base sequence number
     * @param baseOffset          The base (first) offset
     * @param lastOffset          The last offset (inclusive)
     * @param partitionLeaderEpoch The partition leader epoch
     * @param timestampType       The timestamp type
     * @param timestamp           The timestamp value
     * @param isTransactional     Whether this is a transactional batch
     * @param isControlRecord     Whether this is a control batch
     */
    public static void writeEmptyHeader(ByteBuffer buffer,
                                        byte magic,
                                        long producerId,
                                        short producerEpoch,
                                        int baseSequence,
                                        long baseOffset,
                                        long lastOffset,
                                        int partitionLeaderEpoch,
                                        TimestampType timestampType,
                                        long timestamp,
                                        boolean isTransactional,
                                        boolean isControlRecord) {
        int offsetDelta = (int) (lastOffset - baseOffset);
        writeHeader(buffer, baseOffset, offsetDelta, DefaultRecordBatch.RECORD_BATCH_OVERHEAD, magic,
                    CompressionType.NONE, timestampType, RecordBatch.NO_TIMESTAMP, timestamp, producerId,
                    producerEpoch, baseSequence, isTransactional, isControlRecord, false, partitionLeaderEpoch, 0);
    }

    /**
     * Writes a complete batch header to a ByteBuffer, including CRC computation.
     * Used during batch serialization in {@link MemoryRecordsBuilder}.
     *
     * <p><strong>Buffer positioning:</strong> Writes at the buffer's current position and
     * advances the position by {@link #RECORD_BATCH_OVERHEAD} bytes.
     *
     * @param buffer                  The target ByteBuffer
     * @param baseOffset              The first offset in the batch
     * @param lastOffsetDelta         The delta from base offset to last offset (record count - 1)
     * @param sizeInBytes             Total batch size including overhead
     * @param magic                   The magic version
     * @param compressionType         The compression codec
     * @param timestampType           The timestamp type
     * @param baseTimestamp           The base (first) timestamp
     * @param maxTimestamp            The maximum timestamp
     * @param producerId              The producer id
     * @param epoch                   The producer epoch
     * @param sequence                The base sequence number
     * @param isTransactional         Whether batch is transactional
     * @param isControlBatch          Whether batch is a control batch
     * @param isDeleteHorizonSet      Whether delete horizon flag is set
     * @param partitionLeaderEpoch    The partition leader epoch
     * @param numRecords              The count of records in this batch
     * @throws IllegalArgumentException if magic is less than {@link RecordBatch#CURRENT_MAGIC_VALUE}
     *                                  or if baseTimestamp is invalid
     */
    public static void writeHeader(ByteBuffer buffer,
                                   long baseOffset,
                                   int lastOffsetDelta,
                                   int sizeInBytes,
                                   byte magic,
                                   CompressionType compressionType,
                                   TimestampType timestampType,
                                   long baseTimestamp,
                                   long maxTimestamp,
                                   long producerId,
                                   short epoch,
                                   int sequence,
                                   boolean isTransactional,
                                   boolean isControlBatch,
                                   boolean isDeleteHorizonSet,
                                   int partitionLeaderEpoch,
                                   int numRecords) {
        if (magic < RecordBatch.CURRENT_MAGIC_VALUE)
            throw new IllegalArgumentException("Invalid magic value " + magic);
        if (baseTimestamp < 0 && baseTimestamp != NO_TIMESTAMP)
            throw new IllegalArgumentException("Invalid message timestamp " + baseTimestamp);

        short attributes = computeAttributes(compressionType, timestampType, isTransactional, isControlBatch, isDeleteHorizonSet);

        int position = buffer.position();
        buffer.putLong(position + BASE_OFFSET_OFFSET, baseOffset);
        buffer.putInt(position + LENGTH_OFFSET, sizeInBytes - LOG_OVERHEAD);
        buffer.putInt(position + PARTITION_LEADER_EPOCH_OFFSET, partitionLeaderEpoch);
        buffer.put(position + MAGIC_OFFSET, magic);
        buffer.putShort(position + ATTRIBUTES_OFFSET, attributes);
        buffer.putLong(position + BASE_TIMESTAMP_OFFSET, baseTimestamp);
        buffer.putLong(position + MAX_TIMESTAMP_OFFSET, maxTimestamp);
        buffer.putInt(position + LAST_OFFSET_DELTA_OFFSET, lastOffsetDelta);
        buffer.putLong(position + PRODUCER_ID_OFFSET, producerId);
        buffer.putShort(position + PRODUCER_EPOCH_OFFSET, epoch);
        buffer.putInt(position + BASE_SEQUENCE_OFFSET, sequence);
        buffer.putInt(position + RECORDS_COUNT_OFFSET, numRecords);
        long crc = Crc32C.compute(buffer, ATTRIBUTES_OFFSET, sizeInBytes - ATTRIBUTES_OFFSET);
        buffer.putInt(position + CRC_OFFSET, (int) crc);
        buffer.position(position + RECORD_BATCH_OVERHEAD);
    }

    @Override
    public String toString() {
        return "RecordBatch(magic=" + magic() + ", offsets=[" + baseOffset() + ", " + lastOffset() + "], " +
                "sequence=[" + baseSequence() + ", " + lastSequence() + "], " +
                "partitionLeaderEpoch=" + partitionLeaderEpoch() + ", " +
                "isTransactional=" + isTransactional() + ", isControlBatch=" + isControlBatch() + ", " +
                "compression=" + compressionType() + ", timestampType=" + timestampType() + ", crc=" + checksum() + ")";
    }

    /**
     * Computes the serialized size of a batch containing the given records.
     *
     * <p><strong>Performance note:</strong> This method iterates through all records to account
     * for the variable-length encoding of individual record sizes. Use with caution on large
     * record collections.
     *
     * @param baseOffset The base offset for the batch
     * @param records    The records to be included
     * @return The total size in bytes including batch overhead
     */
    public static int sizeInBytes(long baseOffset, Iterable<Record> records) {
        Iterator<Record> iterator = records.iterator();
        if (!iterator.hasNext())
            return 0;

        int size = RECORD_BATCH_OVERHEAD;
        Long baseTimestamp = null;
        while (iterator.hasNext()) {
            Record record = iterator.next();
            int offsetDelta = (int) (record.offset() - baseOffset);
            if (baseTimestamp == null)
                baseTimestamp = record.timestamp();
            long timestampDelta = record.timestamp() - baseTimestamp;
            size += DefaultRecord.sizeInBytes(offsetDelta, timestampDelta, record.key(), record.value(),
                    record.headers());
        }
        return size;
    }

    /**
     * Computes the serialized size of a batch containing the given simple records.
     *
     * @param records The {@link SimpleRecord}s to be included
     * @return The total size in bytes including batch overhead
     */
    public static int sizeInBytes(Iterable<SimpleRecord> records) {
        Iterator<SimpleRecord> iterator = records.iterator();
        if (!iterator.hasNext())
            return 0;

        int size = RECORD_BATCH_OVERHEAD;
        int offsetDelta = 0;
        Long baseTimestamp = null;
        while (iterator.hasNext()) {
            SimpleRecord record = iterator.next();
            if (baseTimestamp == null)
                baseTimestamp = record.timestamp();
            long timestampDelta = record.timestamp() - baseTimestamp;
            size += DefaultRecord.sizeInBytes(offsetDelta++, timestampDelta, record.key(), record.value(),
                    record.headers());
        }
        return size;
    }

    /**
     * Get an upper bound on the size of a batch with only a single record using a given key and value.
     * This is only an estimate because it does not account for additional overhead from the compression
     * algorithm used.
     *
     * @param key     The record key, or null for a tombstone
     * @param value   The record value
     * @param headers The record headers array
     * @return An upper bound on the batch size in bytes
     */
    static int estimateBatchSizeUpperBound(ByteBuffer key, ByteBuffer value, Header[] headers) {
        return RECORD_BATCH_OVERHEAD + DefaultRecord.recordSizeUpperBound(key, value, headers);
    }

    /**
     * Increments a sequence number by a given amount, handling wraparound at {@link Integer#MAX_VALUE}.
     *
     * @param sequence  The current sequence number
     * @param increment The amount to increment by
     * @return The incremented sequence number, wrapping around at MAX_VALUE
     */
    public static int incrementSequence(int sequence, int increment) {
        if (sequence > Integer.MAX_VALUE - increment)
            return increment - (Integer.MAX_VALUE - sequence) - 1;
        return sequence + increment;
    }

    /**
     * Decrements a sequence number by a given amount, handling wraparound at 0.
     *
     * @param sequence The current sequence number
     * @param decrement The amount to decrement by
     * @return The decremented sequence number, wrapping around at 0
     */
    public static int decrementSequence(int sequence, int decrement) {
        if (sequence < decrement)
            return Integer.MAX_VALUE - (decrement - sequence) + 1;
        return sequence - decrement;
    }

    // visible for testing
    abstract class RecordIterator implements CloseableIterator<Record> {
        private final Long logAppendTime;
        private final long baseOffset;
        private final long baseTimestamp;
        private final int baseSequence;
        private final int numRecords;
        private int readRecords = 0;

        RecordIterator() {
            this.logAppendTime = timestampType() == TimestampType.LOG_APPEND_TIME ? maxTimestamp() : null;
            this.baseOffset = baseOffset();
            this.baseTimestamp = baseTimestamp();
            this.baseSequence = baseSequence();
            int numRecords = count();
            if (numRecords < 0)
                throw new InvalidRecordException("Found invalid record count " + numRecords + " in magic v" +
                        magic() + " batch");
            this.numRecords = numRecords;
        }

        @Override
        public boolean hasNext() {
            return readRecords < numRecords;
        }

        @Override
        public Record next() {
            if (readRecords >= numRecords)
                throw new NoSuchElementException();

            readRecords++;
            Record rec = readNext(baseOffset, baseTimestamp, baseSequence, logAppendTime);
            if (readRecords == numRecords) {
                // Validate that the actual size of the batch is equal to declared size
                // by checking that after reading declared number of items, there no items left
                // (overflow case, i.e. reading past buffer end is checked elsewhere).
                if (!ensureNoneRemaining())
                    throw new InvalidRecordException("Incorrect declared batch size, records still remaining in file");
            }
            return rec;
        }

        protected abstract Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime);

        protected abstract boolean ensureNoneRemaining();

        @Override
        public void remove() {
            throw new UnsupportedOperationException();
        }

    }

    // visible for testing
    abstract class StreamRecordIterator extends RecordIterator {
        private final InputStream inputStream;

        StreamRecordIterator(InputStream inputStream) {
            super();
            this.inputStream = inputStream;
        }

        abstract Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException;

        @Override
        protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
            try {
                return doReadRecord(baseOffset, baseTimestamp, baseSequence, logAppendTime);
            } catch (IllegalArgumentException e) {
                throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached", e);
            } catch (IOException e) {
                throw new KafkaException("Failed to decompress record stream", e);
            }
        }

        @Override
        protected boolean ensureNoneRemaining() {
            try {
                return inputStream.read() == -1;
            } catch (IOException e) {
                throw new KafkaException("Error checking for remaining bytes after reading batch", e);
            }
        }

        @Override
        public void close() {
            try {
                inputStream.close();
            } catch (IOException e) {
                throw new KafkaException("Failed to close record stream", e);
            }
        }
    }

    static class DefaultFileChannelRecordBatch extends FileLogInputStream.FileChannelRecordBatch {

        DefaultFileChannelRecordBatch(long offset,
                                      byte magic,
                                      FileRecords fileRecords,
                                      int position,
                                      int batchSize) {
            super(offset, magic, fileRecords, position, batchSize);
        }

        @Override
        protected RecordBatch toMemoryRecordBatch(ByteBuffer buffer) {
            return new DefaultRecordBatch(buffer);
        }

        @Override
        public long baseOffset() {
            return offset;
        }

        @Override
        public long lastOffset() {
            return loadBatchHeader().lastOffset();
        }

        @Override
        public long producerId() {
            return loadBatchHeader().producerId();
        }

        @Override
        public short producerEpoch() {
            return loadBatchHeader().producerEpoch();
        }

        @Override
        public int baseSequence() {
            return loadBatchHeader().baseSequence();
        }

        @Override
        public int lastSequence() {
            return loadBatchHeader().lastSequence();
        }

        @Override
        public Integer countOrNull() {
            return loadBatchHeader().countOrNull();
        }

        @Override
        public boolean isTransactional() {
            return loadBatchHeader().isTransactional();
        }

        @Override
        public OptionalLong deleteHorizonMs() {
            return loadBatchHeader().deleteHorizonMs();
        }

        @Override
        public boolean isControlBatch() {
            return loadBatchHeader().isControlBatch();
        }

        @Override
        public int partitionLeaderEpoch() {
            return loadBatchHeader().partitionLeaderEpoch();
        }

        @Override
        protected int headerSize() {
            return RECORD_BATCH_OVERHEAD;
        }
    }

}

arguments.old_string:
/**
 * A record batch is a container for records. In old versions of the record format (versions 0 and 1),
 * a batch consisted always of a single record if no compression was enabled, but could contain
 * many records otherwise. Newer versions (magic versions 2 and above) will generally contain many records
 * regardless of compression.
 */
public interface RecordBatch extends Iterable<Record> {

    /**
     * The "magic" values
     */
    byte MAGIC_VALUE_V0 = 0;
    byte MAGIC_VALUE_V1 = 1;
    byte MAGIC_VALUE_V2 = 2;

    /**
     * The current "magic" value
     */
    byte CURRENT_MAGIC_VALUE = MAGIC_VALUE_V2;

    /**
     * Timestamp value for records without a timestamp
     */
    long NO_TIMESTAMP = -1L;

    /**
     * Values used in the v2 record format by non-idempotent/non-transactional producers or when
     * up-converting from an older format.
     */
    long NO_PRODUCER_ID = -1L;
    short NO_PRODUCER_EPOCH = -1;
    int NO_SEQUENCE = -1;

    /**
     * Used to indicate an unknown leader epoch, which will be the case when the record set is
     * first created by the producer.
     */
    int NO_PARTITION_LEADER_EPOCH = -1;

    /**
     * Check whether the checksum of this batch is correct.
     *
     * @return true If so, false otherwise
     */
    boolean isValid();

    /**
     * Raise an exception if the checksum is not valid.
     */
    void ensureValid();

    /**
     * Get the checksum of this record batch, which covers the batch header as well as all of the records.
     *
     * @return The 4-byte unsigned checksum represented as a long
     */
    long checksum();

    /**
     * Get the max timestamp or log append time of this record batch.
     *
     * If the timestamp type is create time, this is the max timestamp among all records contained in this batch and
     * the value is updated during compaction.
     *
     * @return The max timestamp
     */
    long maxTimestamp();

    /**
     * Get the timestamp type of this record batch. This will be {@link TimestampType#NO_TIMESTAMP_TYPE}
     * if the batch has magic 0.
     *
     * @return The timestamp type
     */
    TimestampType timestampType();

    /**
     * Get the base offset contained in this record batch. For magic version prior to 2, the base offset will
     * always be the offset of the first message in the batch. This generally requires deep iteration and will
     * return the offset of the first record in the record batch. For magic version 2 and above, this will return
     * the first offset of the original record batch (i.e. prior to compaction). For non-compacted topics, the
     * behavior is equivalent.
     *
     * Because this requires deep iteration for older magic versions, this method should be used with
     * caution. Generally {@link #lastOffset()} is safer since access is efficient for all magic versions.
     *
     * @return The base offset of this record batch (which may or may not be the offset of the first record
     *         as described above).
     */
    long baseOffset();

    /**
     * Get the last offset in this record batch (inclusive). Just like {@link #baseOffset()}, the last offset
     * always reflects the offset of the last record in the original batch, even if it is removed during log
     * compaction.
     *
     * @return The offset of the last record in this batch
     */
    long lastOffset();

    /**
     * Get the offset following this record batch (i.e. the last offset contained in this batch plus one).
     *
     * @return the next consecutive offset following this batch
     */
    long nextOffset();

    /**
     * Get the record format version of this record batch (i.e its magic value).
     *
     * @return the magic byte
     */
    byte magic();

    /**
     * Get the producer id for this log record batch. For older magic versions, this will return -1.
     *
     * @return The producer id or -1 if there is none
     */
    long producerId();

    /**
     * Get the producer epoch for this log record batch.
     *
     * @return The producer epoch, or -1 if there is none
     */
    short producerEpoch();

    /**
     * Does the batch have a valid producer id set.
     */
    boolean hasProducerId();

    /**
     * Get the base sequence number of this record batch. Like {@link #baseOffset()}, this value is not
     * affected by compaction: it always retains the base sequence number from the original batch.
     *
     * @return The first sequence number or -1 if there is none
     */
    int baseSequence();

    /**
     * Get the last sequence number of this record batch. Like {@link #lastOffset()}, the last sequence number
     * always reflects the sequence number of the last record in the original batch, even if it is removed during log
     * compaction.
     *
     * @return The last sequence number or -1 if there is none
     */
    int lastSequence();

    /**
     * Get the compression type of this record batch.
     *
     * @return The compression type
     */
    CompressionType compressionType();

    /**
     * Get the size in bytes of this batch, including the size of the record and the batch overhead.
     * @return The size in bytes of this batch
     */
    int sizeInBytes();

    /**
     * Get the count if it is efficiently supported by the record format (which is only the case
     * for magic 2 and higher).
     *
     * @return The number of records in the batch or null for magic versions 0 and 1.
     */
    Integer countOrNull();

    /**
     * Check whether this record batch is compressed.
     * @return true if so, false otherwise
     */
    boolean isCompressed();

    /**
     * Write this record batch into a buffer.
     * @param buffer The buffer to write the batch to
     */
    void writeTo(ByteBuffer buffer);

    /**
     * Whether or not this record batch is part of a transaction.
     * @return true if it is, false otherwise
     */
    boolean isTransactional();

    /**
     * Get the delete horizon, returns OptionalLong.EMPTY if the first timestamp is not the delete horizon
     * @return timestamp of the delete horizon
     */
    OptionalLong deleteHorizonMs();

    /**
     * Get the partition leader epoch of this record batch.
     * @return The leader epoch or -1 if it is unknown
     */
    int partitionLeaderEpoch();

    /**
     * Return a streaming iterator which basically delays decompression of the record stream until the records
     * are actually asked for using {@link Iterator#next()}. If the message format does not support streaming
     * iteration, then the normal iterator is returned. Either way, callers should ensure that the iterator is closed.
     *
     * @param decompressionBufferSupplier The supplier of ByteBuffer(s) used for decompression if supported.
     *                                    For small record batches, allocating a potentially large buffer (64 KB for LZ4)
     *                                    will dominate the cost of decompressing and iterating over the records in the
     *                                    batch. As such, a supplier that reuses buffers will have a significant
     *                                    performance impact.
     * @return The closeable iterator
     */
    CloseableIterator<Record> streamingIterator(BufferSupplier decompressionBufferSupplier);

    /**
     * Check whether this is a control batch (i.e. whether the control bit is set in the batch attributes).
     * For magic versions prior to 2, this is always false.
     *
     * @return Whether this is a batch containing control records
     */
    boolean isControlBatch();

    /**
     * iterate all records to find the offset of max timestamp.
     * noted:
     * 1) that the earliest offset will return if there are multi records having same (max) timestamp
     * 2) it always returns None if the {@link RecordBatch#magic()} is equal to {@link RecordBatch#MAGIC_VALUE_V0}
     * @return offset of max timestamp
     */
    default Optional<Long> offsetOfMaxTimestamp() {
        if (magic() == RecordBatch.MAGIC_VALUE_V0) return Optional.empty();
        long maxTimestamp = maxTimestamp();
        try (CloseableIterator<Record> iter = streamingIterator(BufferSupplier.create())) {
            while (iter.hasNext()) {
                Record record = iter.next();
                if (maxTimestamp == record.timestamp()) return Optional.of(record.offset());
            }
        }
        return Optional.empty();
    }
}

